define('taoItems/controller/items/edit',['jquery', 'i18n', 'module', 'layout/actions', 'ui/lock', 'layout/section', 'util/url'], function ($, __, module, actions, lock, section, urlUtil) {
  'use strict';
  var editItemController = {
    start() {
      var config = module.config();
      var maxButtons = 10;
      var getPreviewId = idx => "item-preview".concat(idx ? "-".concat(idx) : '');
      var previewActions = [];
      for (var i = 0; i < maxButtons; i++) {
        var action = actions.getBy(getPreviewId(i));
        if (!action) {
          break;
        }
        previewActions.push(action);
      }
      previewActions.forEach(previewAction => {
        previewAction.state.disabled = !config.isPreviewEnabled;
      });
      var authoringAction = actions.getBy('item-authoring');
      if (authoringAction) {
        authoringAction.state.disabled = !config.isAuthoringEnabled;
      }
      actions.updateState();
      $('#lock-box').each(function () {
        lock($(this)).register();
      });
      section.off('show').on('show', sectionContext => {
        if (sectionContext.id === 'manage_items') {
          actions.exec('item-properties');
        }
      });
      var parsedUrl = urlUtil.parse(window.location.href);
      var autoAction = parsedUrl.query.autoAction;
      if (autoAction && config.isAuthoringEnabled && actions.getBy(autoAction)) {
        actions.exec(autoAction);
      }
    }
  };
  return editItemController;
});
