define('taoItems/previewer/factory',['context', 'module', 'core/providerLoader', 'core/providerRegistry', 'taoItems/previewer/adapter/legacy'], function (context, module, providerLoaderFactory, providerRegistry, legacyPreviewer) {
  'use strict';
  function previewerFactory(type, uri, state) {
    var config = arguments.length > 3 && arguments[3] !== undefined ? arguments[3] : {};
    Object.assign(config, module.config());
    return providerLoaderFactory().addList(config.previewers).load(context.bundle).then(function (providers) {
      previewerFactory.registerProvider(legacyPreviewer.name, legacyPreviewer);
      providers.forEach(provider => {
        previewerFactory.registerProvider(provider.name, provider);
      });
    }).then(function () {
      return previewerFactory.getProvider(type || legacyPreviewer.name);
    }).then(function (provider) {
      return provider.init(uri, state, config);
    });
  }
  return providerRegistry(previewerFactory, function validateProvider(provider) {
    if (typeof provider.init !== 'function') {
      throw new TypeError('The previewer provider MUST have a init() method');
    }
    return true;
  });
});
