define('taoItems/component/category/switch',['i18n', 'ui/component', 'tpl!taoItems/component/category/switch'], function (__, component, switchTpl) {
  'use strict';
  var titles = {
    expose: __('Expose the property value to create automated categories.'),
    unexpose: __('The property is exposed to category addition.&#13Remove exposition ?')
  };
  return function categorySwitchFactory($container, propertyId, exposed) {
    var categorySwitchComponent;
    if (!propertyId) {
      throw new TypeError('We need the property id');
    }
    categorySwitchComponent = component({
      setExposed: function setExposed(value) {
        if (!this.is('disabled')) {
          this.setState('exposed', !!value);
          if (this.is('rendered')) {
            if (value) {
              this.getElement().removeClass('placeholder').addClass('txt-success').attr('title', titles.unexpose);
            } else {
              this.getElement().removeClass('txt-success').addClass('placeholder').attr('title', titles.expose);
            }
          }
        }
        return this;
      },
      isExposed: function isExposed() {
        return this.is('exposed');
      }
    }, {}).on('init', function () {
      this.setState('exposed', exposed);
      this.render($container);
    }).on('render', function () {
      var self = this;
      var $component = this.getElement();
      this.setExposed(exposed);
      $component.off('click').on('click', function (e) {
        e.preventDefault();
        if (!self.is('disabled')) {
          self.trigger('requestChange', self.config.id, !self.is('exposed'));
        }
      });
    });
    setTimeout(() => {
      categorySwitchComponent.setTemplate(switchTpl).init({
        id: propertyId
      });
    }, 0);
    return categorySwitchComponent;
  };
});
