define('taoItems/preview/actionBarHook',['jquery', 'core/errorHandler', 'core/promise'], function ($, errorHandler, Promise) {
  'use strict';
  var _ns = '.previewActionBarHook';
  var tools = {};
  var $toolContainers = $();
  $(document).off('.preview').on('itemunload.preview', function () {
    $toolContainers.each(function () {
      var $toolContainer = $(this);
      tools.forEach((tool, id) => {
        var $btn = $toolContainer.children("[data-control=\"".concat(id, "\"]"));
        if ($btn.length) {
          tool.clear($btn);
          $btn.remove();
        }
      });
    });
  });
  function isValidConfig(toolconfig) {
    return !!(_.isObject(toolconfig) && toolconfig.hook);
  }
  function triggerItemLoaded(tool) {
    if (tool && tool.itemLoaded) {
      tool.itemLoaded();
    }
  }
  function initExtraButtons($toolContainer, id, toolconfig) {
    if (_.isString(toolconfig)) {
      toolconfig = {
        hook: toolconfig
      };
    }
    tools[id] = null;
    $toolContainers = $toolContainers.add($toolContainer);
    return new Promise(function (resolve) {
      if (isValidConfig(toolconfig)) {
        require([toolconfig.hook], function (hook) {
          var $button;
          var $existingBtn;
          if (isValidHook(hook)) {
            hook.init(id, toolconfig);
            $existingBtn = $toolContainer.children('[data-control="' + id + '"]');
            if ($existingBtn.length) {
              hook.clear($existingBtn);
              $existingBtn.remove();
            }
            tools[id] = hook;
            $button = hook.render();
            _appendInOrder($toolContainer, $button);
            $button.trigger('ready' + _ns, [hook]);
            triggerItemLoaded(hook);
            resolve(hook);
          } else {
            errorHandler.throw(_ns, 'invalid hook format');
            resolve(null);
          }
        }, function (e) {
          errorHandler.throw(_ns, 'the hook amd module cannot be found');
          resolve(null);
        });
      } else {
        errorHandler.throw(_ns, 'invalid tool config format');
        resolve(null);
      }
    });
  }
  function _appendInOrder($container, $button) {
    var $after, $before;
    var order = $button.data('order');
    if ('last' === order) {
      $container.append($button);
    } else if ('first' === order) {
      $container.prepend($button);
    } else {
      order = _.parseInt(order);
      if (!_.isNaN(order)) {
        $container.children('.action').each(function () {
          var $btn = $(this),
            _order = $btn.data('order');
          if ('last' === _order) {
            $before = $btn;
            $after = null;
          } else if ('first' === _order) {
            $before = null;
            $after = $btn;
          } else {
            _order = _.parseInt(_order);
            if (_.isNaN(_order) || _order > order) {
              $before = $btn;
              $after = null;
              return false;
            } else if (_order === order) {
              $after = $btn;
            } else if (_order < order) {
              $after = $btn;
              $before = null;
            }
          }
        });
        if ($after) {
          $after.after($button);
        } else if ($before) {
          $before.before($button);
        } else {
          $container.append($button);
        }
      } else {
        $container.append($button);
      }
    }
  }
  function isValidHook(hook) {
    return _.isObject(hook) && _(['init', 'render', 'clear', 'isVisible']).reduce(function (result, method) {
      return result && _.isFunction(hook[method]);
    }, true);
  }
  return {
    isValid: isValidConfig,
    initExtraButtons: initExtraButtons
  };
});
