define('taoItems/previewer/adapter/legacy',['util/url', 'taoItems/preview/preview'], function (urlHelper, preview) {
  'use strict';
  return {
    name: 'legacy',
    init: function init(uri, state, config) {
      if (typeof uri === 'object' && uri.uri) {
        uri = uri.uri;
      }
      window.scrollTo(0, 0);
      preview.init(urlHelper.route('forwardMe', 'ItemPreview', 'taoItems', {
        uri: uri
      }), state);
      preview.show();
      return preview;
    }
  };
});
